class Solution(object):
    def findEvenNumbers(self, digits):
        from collections import Counter
        freq = Counter(digits)
        result = []
        for num in range(100, 1000, 2):
            temp_freq = freq.copy()
            valid = True
            for digit in str(num):
                if temp_freq[int(digit)] > 0:
                    temp_freq[int(digit)] -= 1
                else:
                    valid = False
                    break
            if valid:
                result.append(num)
        return result
